import React from "react";
import { FaStar } from "react-icons/fa";

function Shop() {
  const products = [
    { id: 1, name: "Smartphone", price: 499, rating: 4, image: "https://via.placeholder.com/200?text=Smartphone" },
    { id: 2, name: "Laptop", price: 899, rating: 5, image: "https://via.placeholder.com/200?text=Laptop" },
    { id: 3, name: "Headphones", price: 99, rating: 3, image: "https://via.placeholder.com/200?text=Headphones" },
    { id: 4, name: "Smartwatch", price: 199, rating: 4, image: "https://via.placeholder.com/200?text=Smartwatch" },
    { id: 5, name: "Tablet", price: 299, rating: 4, image: "https://via.placeholder.com/200?text=Tablet" },
    { id: 6, name: "Camera", price: 599, rating: 5, image: "https://via.placeholder.com/200?text=Camera" },
    { id: 7, name: "Ps5", price: 49, rating: 2, image: "https://via.placeholder.com/200?text=Ps5" },
    { id: 8, name: "Mouse", price: 29, rating: 3, image: "https://via.placeholder.com/200?text=Mouse" },
    { id: 9, name: "Speaker", price: 79, rating: 4, image: "https://via.placeholder.com/200?text=Speaker" },
    { id: 10, name: "Monitor", price: 249, rating: 4, image: "https://via.placeholder.com/200?text=Monitor" },
    { id: 11, name: "Controller", price: 149, rating: 3, image: "https://via.placeholder.com/200?text=Controller" },
    { id: 12, name: "Airpods", price: 89, rating: 4, image: "https://via.placeholder.com/200?text=Airpods" },
    { id: 13, name: "External HDD", price: 129, rating: 4, image: "https://via.placeholder.com/200?text=External+HDD" },
    { id: 14, name: "USB Drive", price: 19, rating: 3, image: "https://via.placeholder.com/200?text=USB+Drive" },
    { id: 15, name: "Charger", price: 39, rating: 4, image: "https://via.placeholder.com/200?text=Charger" },
  ];

  const handleAddToCart = (product) => {
    alert(`${product.name} added to cart!`);
  };

  const handleBuyNow = (product) => {
    alert(`Proceed to buy ${product.name}`);
  };

  const renderStars = (rating) => {
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <FaStar
          key={i}
          size={14}
          color={i <= rating ? "#facc15" : "#d1d5db"} // yellow = filled, gray = empty
          style={{ marginRight: "2px" }}
        />
      );
    }
    return stars;
  };

  return (
    <div className="shop-container" style={{ padding: "20px" }}>
      <h2 style={{ marginBottom: "20px" }}>All Products</h2>
      <div
        className="products-grid"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(5, 1fr)", // 5 items per row
          gap: "15px",
        }}
      >
        {products.map((product) => (
          <div
            key={product.id}
            className="product-card"
            style={{
              border: "1px solid #ccc",
              borderRadius: "8px",
              padding: "10px",
              textAlign: "center",
              boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
              display: "flex",
              flexDirection: "column",
              height: "320px",
            }}
          >
            {/* Image + Details */}
            <div style={{ flex: "1", display: "flex", flexDirection: "column", justifyContent: "center" }}>
              <img
                src={product.image}
                alt={product.name}
                style={{
                  width: "100%",
                  height: "140px",
                  objectFit: "contain",
                  marginBottom: "10px",
                  borderRadius: "5px",
                }}
              />
              <h3 style={{ fontSize: "16px", margin: "5px 0" }}>{product.name}</h3>
              <p style={{ fontSize: "14px", color: "#555", margin: "5px 0" }}>
                ${product.price}
              </p>
              <div style={{ display: "flex", justifyContent: "center" }}>
                {renderStars(product.rating)}
              </div>
            </div>

            {/* Buttons */}
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                gap: "8px",
                marginTop: "10px",
              }}
            >
              <button
                style={{
                  flex: 1,
                  padding: "8px 0",
                  backgroundColor: "#2563eb",
                  color: "#fff",
                  border: "none",
                  borderRadius: "5px",
                  cursor: "pointer",
                }}
                onClick={() => handleAddToCart(product)}
              >
                Add to Cart
              </button>
              <button
                style={{
                  flex: 1,
                  padding: "8px 0",
                  backgroundColor: "#16a34a",
                  color: "#fff",
                  border: "none",
                  borderRadius: "5px",
                  cursor: "pointer",
                }}
                onClick={() => handleBuyNow(product)}
              >
                Buy Now
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Shop;
